import{GAME_CONFIG}from"../config.js";class ActionQueue{constructor(t){this.entity=t,this.queue=[]}addMoveAction(t,e,u,i,r="move"){this.takeAP(Number(i)),this.queue.push({type:r,state:u,q:Number(t),r:Number(e),apCost:Number(i)})}addShootAction(t,e,u,i){this.takeAP(Number(u)),this.queue.push({type:"shoot",targetQ:Number(t),targetR:Number(e),targetID:i,apCost:Number(u)})}takeAP(t){this.entity.currentAP-=t}clear(){this.queue=[],this.isExecutingAction=!1}}export{ActionQueue};